--
-- Table structure for table `jobs`
--

DROP TABLE IF EXISTS `jobs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `jobs` (
  `job_id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `job_title` varchar(250) COLLATE utf8_unicode_ci NOT NULL,
  `job_description` varchar(4000) COLLATE utf8_unicode_ci NOT NULL,
  `job_creation_date` datetime NOT NULL,
  `job_deadline_date` datetime NOT NULL,
  `job_price` int NOT NULL,
  `freelancer_id` int DEFAULT NULL,
  `job_completion_date` datetime DEFAULT NULL,
  `job_completion_rating` int DEFAULT NULL,
  `job_completion_message` varchar(1000) COLLATE utf8_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`job_id`),
  KEY `user_id_INDEX` (`user_id`) /*!80000 INVISIBLE */,
  KEY `freelancer_id_INDEX` (`freelancer_id`),
  KEY `job_creation_date_INDEX` (`job_creation_date`),
  FULLTEXT KEY `job_search_FULLTEXT` (`job_title`,`job_description`),
  CONSTRAINT `fk_jobs_freelancers1` FOREIGN KEY (`freelancer_id`) REFERENCES `freelancers` (`freelancer_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_jobs_users2` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=204 DEFAULT CHARSET=utf8mb3 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

