DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `users` (
  `user_id` int NOT NULL AUTO_INCREMENT,
  `user_first_name` varchar(45) COLLATE utf8_unicode_ci NOT NULL,
  `user_last_name` varchar(45) COLLATE utf8_unicode_ci NOT NULL,
  `user_email` varchar(120) COLLATE utf8_unicode_ci NOT NULL,
  `user_email_visibility` tinyint NOT NULL DEFAULT '1',
  `user_phone_number` varchar(20) COLLATE utf8_unicode_ci NOT NULL,
  `user_phone_number_visibility` tinyint NOT NULL DEFAULT '1',
  `user_password` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `user_date_of_birth` date NOT NULL,
  `user_gender` varchar(1) COLLATE utf8_unicode_ci NOT NULL,
  `user_account_creation_date` date NOT NULL,
  `user_city` varchar(30) COLLATE utf8_unicode_ci NOT NULL,
  `user_specific_address` varchar(200) COLLATE utf8_unicode_ci DEFAULT NULL,
  `user_profile_picture_path` varchar(200) COLLATE utf8_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`user_id`),
  UNIQUE KEY `user_email_UNIQUE` (`user_email`),
  UNIQUE KEY `user_phone_number_UNIQUE` (`user_phone_number`),
  FULLTEXT KEY `user_full_name_FULLTEXT` (`user_first_name`,`user_last_name`)
) ENGINE=InnoDB AUTO_INCREMENT=101 DEFAULT CHARSET=utf8mb3 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

