CREATE DEFINER=`a993c8_freelan`@`%` PROCEDURE `drop_all_triggers`()
BEGIN

DECLARE done INT DEFAULT FALSE;
DECLARE trigger_name VARCHAR(300);
DECLARE cur CURSOR FOR SELECT trigger_name FROM information_schema.triggers WHERE trigger_schema = DATABASE();
DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

OPEN cur;
